/**
 * Product Service Tests
 *
 * Unit tests for ProductService covering:
 * - Product CRUD operations
 * - Variant management
 * - Modifier management
 * - Allergen associations
 * - Nutrition information
 * - Availability and featured status
 *
 * @module modules/menu/__tests__/product.service.spec
 */

import { describe, it, expect, beforeEach, vi, type Mock } from 'vitest';

import { ProductService } from '@/modules/menu/product.service';
import { AppException } from '@/core/exceptions/app.exception';
import type { ProductRepository, PaginatedResult } from '@/modules/menu/product.repository';
import type { CategoryRepository } from '@/modules/menu/category.repository';
import type { EventService } from '@/core/services/event.service';
import type {
  Product,
  ProductWithRelations,
  ProductVariant,
  ProductModifier,
  NutritionInfo,
  Category,
} from '@/modules/menu/menu.types';

// -----------------------------------------------------------------------------
// Mock Factories
// -----------------------------------------------------------------------------

/**
 * Creates a mock ProductRepository
 */
function createMockProductRepository(): {
  findAll: Mock;
  findAllWithRelations: Mock;
  findAllSummaries: Mock;
  findByCategoryId: Mock;
  findById: Mock;
  findByIdWithRelations: Mock;
  findByIdOrThrow: Mock;
  findBySlug: Mock;
  findFeatured: Mock;
  slugExists: Mock;
  count: Mock;
  createWithRelations: Mock;
  update: Mock;
  reorder: Mock;
  softDelete: Mock;
  restore: Mock;
  findVariants: Mock;
  createVariant: Mock;
  updateVariant: Mock;
  deleteVariant: Mock;
  setDefaultVariant: Mock;
  findModifiers: Mock;
  createModifier: Mock;
  updateModifier: Mock;
  deleteModifier: Mock;
  setAllergens: Mock;
  addAllergen: Mock;
  removeAllergen: Mock;
  findNutritionInfo: Mock;
  upsertNutritionInfo: Mock;
  deleteNutritionInfo: Mock;
} {
  return {
    findAll: vi.fn(),
    findAllWithRelations: vi.fn(),
    findAllSummaries: vi.fn(),
    findByCategoryId: vi.fn(),
    findById: vi.fn(),
    findByIdWithRelations: vi.fn(),
    findByIdOrThrow: vi.fn(),
    findBySlug: vi.fn(),
    findFeatured: vi.fn(),
    slugExists: vi.fn(),
    count: vi.fn(),
    createWithRelations: vi.fn(),
    update: vi.fn(),
    reorder: vi.fn(),
    softDelete: vi.fn(),
    restore: vi.fn(),
    findVariants: vi.fn(),
    createVariant: vi.fn(),
    updateVariant: vi.fn(),
    deleteVariant: vi.fn(),
    setDefaultVariant: vi.fn(),
    findModifiers: vi.fn(),
    createModifier: vi.fn(),
    updateModifier: vi.fn(),
    deleteModifier: vi.fn(),
    setAllergens: vi.fn(),
    addAllergen: vi.fn(),
    removeAllergen: vi.fn(),
    findNutritionInfo: vi.fn(),
    upsertNutritionInfo: vi.fn(),
    deleteNutritionInfo: vi.fn(),
  };
}

/**
 * Creates a mock CategoryRepository
 */
function createMockCategoryRepository(): {
  findByIdOrThrow: Mock;
} {
  return {
    findByIdOrThrow: vi.fn(),
  };
}

/**
 * Creates a mock EventService
 */
function createMockEventService(): {
  emitCustom: Mock;
} {
  return {
    emitCustom: vi.fn(),
  };
}

/**
 * Creates a mock product for testing
 */
function createMockProduct(overrides: Partial<Product> = {}): Product {
  return {
    id: 'prod_123',
    organizationId: 'org_123',
    categoryId: 'cat_123',
    name: 'Test Product',
    slug: 'test-product',
    description: 'A test product',
    shortDescription: null,
    basePrice: 100,
    currency: 'TRY',
    image: null,
    gallery: [],
    isActive: true,
    isAvailable: true,
    isFeatured: false,
    isChefRecommended: false,
    preparationTime: null,
    calories: null,
    spicyLevel: null,
    tags: [],
    sortOrder: 0,
    createdAt: new Date(),
    updatedAt: new Date(),
    deletedAt: null,
    ...overrides,
  };
}

/**
 * Creates a mock product with relations
 */
function createMockProductWithRelations(
  overrides: Partial<ProductWithRelations> = {}
): ProductWithRelations {
  return {
    ...createMockProduct(),
    category: createMockCategory() as any,
    variants: [],
    modifiers: [],
    allergens: [],
    nutritionInfo: null,
    ...overrides,
  };
}

/**
 * Creates a mock category for testing
 */
function createMockCategory(overrides: Partial<Category> = {}): Category {
  return {
    id: 'cat_123',
    organizationId: 'org_123',
    menuId: 'menu_123',
    parentId: null,
    name: 'Test Category',
    slug: 'test-category',
    description: null,
    image: null,
    isActive: true,
    sortOrder: 0,
    createdAt: new Date(),
    updatedAt: new Date(),
    deletedAt: null,
    ...overrides,
  };
}

/**
 * Creates a mock variant for testing
 */
function createMockVariant(overrides: Partial<ProductVariant> = {}): ProductVariant {
  return {
    id: 'var_123',
    productId: 'prod_123',
    name: 'Regular',
    price: 100,
    isDefault: true,
    isAvailable: true,
    sortOrder: 0,
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

/**
 * Creates a mock modifier for testing
 */
function createMockModifier(overrides: Partial<ProductModifier> = {}): ProductModifier {
  return {
    id: 'mod_123',
    productId: 'prod_123',
    name: 'Extra Cheese',
    price: 20,
    isDefault: false,
    isRequired: false,
    maxQuantity: 1,
    sortOrder: 0,
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

/**
 * Creates a mock nutrition info for testing
 */
function createMockNutritionInfo(
  overrides: Partial<NutritionInfo> = {}
): NutritionInfo {
  return {
    id: 'nutri_123',
    productId: 'prod_123',
    calories: 500,
    protein: 25,
    carbohydrates: 50,
    fat: 20,
    fiber: 5,
    sodium: 800,
    sugar: 10,
    servingSize: 250,
    servingUnit: 'g',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

// -----------------------------------------------------------------------------
// Test Suite
// -----------------------------------------------------------------------------

describe('ProductService', () => {
  let service: ProductService;
  let mockProductRepository: ReturnType<typeof createMockProductRepository>;
  let mockCategoryRepository: ReturnType<typeof createMockCategoryRepository>;
  let mockEventService: ReturnType<typeof createMockEventService>;

  const orgId = 'org_123';
  const categoryId = 'cat_123';

  beforeEach(() => {
    mockProductRepository = createMockProductRepository();
    mockCategoryRepository = createMockCategoryRepository();
    mockEventService = createMockEventService();

    service = new ProductService(
      mockProductRepository as unknown as ProductRepository,
      mockCategoryRepository as unknown as CategoryRepository,
      mockEventService as unknown as EventService
    );
  });

  // ---------------------------------------------------------------------------
  // Read Operations Tests
  // ---------------------------------------------------------------------------

  describe('list', () => {
    it('should return paginated products', async () => {
      // Arrange
      const products = [createMockProduct(), createMockProduct({ id: 'prod_456' })];
      const paginatedResult: PaginatedResult<Product> = {
        data: products,
        meta: { page: 1, perPage: 20, total: 2, totalPages: 1 },
      };
      mockProductRepository.findAll.mockResolvedValue(paginatedResult);

      // Act
      const result = await service.list(orgId, { categoryId, page: 1, perPage: 20 });

      // Assert
      expect(result).toEqual(paginatedResult);
      expect(mockProductRepository.findAll).toHaveBeenCalledWith(
        orgId,
        expect.objectContaining({ categoryId })
      );
    });

    it('should filter by active status', async () => {
      // Arrange
      const paginatedResult: PaginatedResult<Product> = {
        data: [createMockProduct({ isActive: true })],
        meta: { page: 1, perPage: 20, total: 1, totalPages: 1 },
      };
      mockProductRepository.findAll.mockResolvedValue(paginatedResult);

      // Act
      await service.list(orgId, { isActive: true });

      // Assert
      expect(mockProductRepository.findAll).toHaveBeenCalledWith(
        orgId,
        expect.objectContaining({ isActive: true })
      );
    });
  });

  describe('getById', () => {
    it('should return product when found', async () => {
      // Arrange
      const product = createMockProduct();
      mockProductRepository.findById.mockResolvedValue(product);

      // Act
      const result = await service.getById(orgId, 'prod_123');

      // Assert
      expect(result).toEqual(product);
    });

    it('should return null when product not found', async () => {
      // Arrange
      mockProductRepository.findById.mockResolvedValue(null);

      // Act
      const result = await service.getById(orgId, 'nonexistent');

      // Assert
      expect(result).toBeNull();
    });
  });

  describe('getByIdWithRelations', () => {
    it('should return product with relations when found', async () => {
      // Arrange
      const productWithRelations = createMockProductWithRelations();
      mockProductRepository.findByIdWithRelations.mockResolvedValue(
        productWithRelations
      );

      // Act
      const result = await service.getByIdWithRelations(orgId, 'prod_123');

      // Assert
      expect(result).toEqual(productWithRelations);
    });

    it('should throw AppException when product not found', async () => {
      // Arrange
      mockProductRepository.findByIdWithRelations.mockResolvedValue(null);

      // Act & Assert
      await expect(
        service.getByIdWithRelations(orgId, 'nonexistent')
      ).rejects.toThrow(AppException);
    });
  });

  describe('getFeatured', () => {
    it('should return featured products', async () => {
      // Arrange
      const featuredProducts = [
        createMockProduct({ isFeatured: true }),
        createMockProduct({ id: 'prod_456', isFeatured: true }),
      ];
      mockProductRepository.findFeatured.mockResolvedValue(featuredProducts);

      // Act
      const result = await service.getFeatured(orgId);

      // Assert
      expect(result).toEqual(featuredProducts);
      expect(mockProductRepository.findFeatured).toHaveBeenCalledWith(orgId, 10);
    });

    it('should respect limit parameter', async () => {
      // Arrange
      mockProductRepository.findFeatured.mockResolvedValue([]);

      // Act
      await service.getFeatured(orgId, 5);

      // Assert
      expect(mockProductRepository.findFeatured).toHaveBeenCalledWith(orgId, 5);
    });
  });

  describe('getByCategoryId', () => {
    it('should return products for a category', async () => {
      // Arrange
      const products = [createMockProduct(), createMockProduct({ id: 'prod_456' })];
      mockCategoryRepository.findByIdOrThrow.mockResolvedValue(createMockCategory());
      mockProductRepository.findByCategoryId.mockResolvedValue(products);

      // Act
      const result = await service.getByCategoryId(orgId, categoryId);

      // Assert
      expect(result).toEqual(products);
      expect(mockCategoryRepository.findByIdOrThrow).toHaveBeenCalledWith(
        categoryId,
        orgId
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Create Operations Tests
  // ---------------------------------------------------------------------------

  describe('create', () => {
    const validCreateData = {
      categoryId,
      name: 'New Product',
      basePrice: 150,
      description: 'A new product',
    };

    it('should create a product successfully', async () => {
      // Arrange
      const createdProduct = createMockProductWithRelations({
        name: validCreateData.name,
        slug: 'new-product',
        basePrice: validCreateData.basePrice,
      });
      mockCategoryRepository.findByIdOrThrow.mockResolvedValue(createMockCategory());
      mockProductRepository.slugExists.mockResolvedValue(false);
      mockProductRepository.createWithRelations.mockResolvedValue(createdProduct);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.create(orgId, validCreateData);

      // Assert
      expect(result.product).toEqual(createdProduct);
      expect(result.message).toContain('successfully');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'product.created',
        expect.objectContaining({
          productId: createdProduct.id,
          categoryId,
          organizationId: orgId,
        })
      );
    });

    it('should verify category exists before creating', async () => {
      // Arrange
      mockCategoryRepository.findByIdOrThrow.mockRejectedValue(
        AppException.notFound('Category', categoryId)
      );

      // Act & Assert
      await expect(service.create(orgId, validCreateData)).rejects.toThrow(
        AppException
      );
      expect(mockProductRepository.createWithRelations).not.toHaveBeenCalled();
    });

    it('should generate unique slug when slug exists', async () => {
      // Arrange
      const createdProduct = createMockProductWithRelations({ slug: 'new-product-1' });
      mockCategoryRepository.findByIdOrThrow.mockResolvedValue(createMockCategory());
      mockProductRepository.slugExists
        .mockResolvedValueOnce(true)
        .mockResolvedValueOnce(false);
      mockProductRepository.createWithRelations.mockResolvedValue(createdProduct);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.create(orgId, validCreateData);

      // Assert
      expect(mockProductRepository.createWithRelations).toHaveBeenCalledWith(
        orgId,
        expect.objectContaining({ slug: 'new-product-1' }),
        undefined,
        undefined,
        [],
        undefined
      );
    });

    it('should throw error when provided slug already exists', async () => {
      // Arrange
      const dataWithSlug = {
        ...validCreateData,
        slug: 'existing-slug',
      };
      mockCategoryRepository.findByIdOrThrow.mockResolvedValue(createMockCategory());
      mockProductRepository.slugExists.mockResolvedValue(true);

      // Act & Assert
      await expect(service.create(orgId, dataWithSlug)).rejects.toThrow(
        AppException
      );
    });

    it('should create product with variants', async () => {
      // Arrange
      const dataWithVariants = {
        ...validCreateData,
        variants: [
          { name: 'Small', price: 100 },
          { name: 'Large', price: 150 },
        ],
      };
      const createdProduct = createMockProductWithRelations({
        variants: [
          createMockVariant({ name: 'Small', price: 100 }),
          createMockVariant({ id: 'var_456', name: 'Large', price: 150 }),
        ] as any,
      });
      mockCategoryRepository.findByIdOrThrow.mockResolvedValue(createMockCategory());
      mockProductRepository.slugExists.mockResolvedValue(false);
      mockProductRepository.createWithRelations.mockResolvedValue(createdProduct);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.create(orgId, dataWithVariants);

      // Assert
      expect(result.product.variants).toHaveLength(2);
    });

    it('should create product with modifiers', async () => {
      // Arrange
      const dataWithModifiers = {
        ...validCreateData,
        modifiers: [{ name: 'Extra Cheese', price: 20 }],
      };
      const createdProduct = createMockProductWithRelations({
        modifiers: [createMockModifier()] as any,
      });
      mockCategoryRepository.findByIdOrThrow.mockResolvedValue(createMockCategory());
      mockProductRepository.slugExists.mockResolvedValue(false);
      mockProductRepository.createWithRelations.mockResolvedValue(createdProduct);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.create(orgId, dataWithModifiers);

      // Assert
      expect(result.product.modifiers).toHaveLength(1);
    });
  });

  // ---------------------------------------------------------------------------
  // Update Operations Tests
  // ---------------------------------------------------------------------------

  describe('update', () => {
    const validUpdateData = {
      name: 'Updated Product',
      basePrice: 200,
    };

    it('should update a product successfully', async () => {
      // Arrange
      const existingProduct = createMockProduct();
      const updatedProduct = createMockProduct({
        name: validUpdateData.name,
        basePrice: validUpdateData.basePrice,
      });
      mockProductRepository.findByIdOrThrow.mockResolvedValue(existingProduct);
      mockProductRepository.update.mockResolvedValue(updatedProduct);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.update(orgId, 'prod_123', validUpdateData);

      // Assert
      expect(result.product).toEqual(updatedProduct);
      expect(result.message).toContain('successfully');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'product.updated',
        expect.objectContaining({
          productId: updatedProduct.id,
        })
      );
    });

    it('should throw error when product not found', async () => {
      // Arrange
      mockProductRepository.findByIdOrThrow.mockRejectedValue(
        AppException.notFound('Product', 'nonexistent')
      );

      // Act & Assert
      await expect(
        service.update(orgId, 'nonexistent', validUpdateData)
      ).rejects.toThrow(AppException);
    });

    it('should verify new category exists when changing category', async () => {
      // Arrange
      const existingProduct = createMockProduct();
      mockProductRepository.findByIdOrThrow.mockResolvedValue(existingProduct);
      mockCategoryRepository.findByIdOrThrow.mockRejectedValue(
        AppException.notFound('Category', 'new_cat')
      );

      // Act & Assert
      await expect(
        service.update(orgId, 'prod_123', { categoryId: 'new_cat' })
      ).rejects.toThrow(AppException);
    });

    it('should check slug uniqueness when changing slug', async () => {
      // Arrange
      const existingProduct = createMockProduct();
      mockProductRepository.findByIdOrThrow.mockResolvedValue(existingProduct);
      mockProductRepository.slugExists.mockResolvedValue(true);

      // Act & Assert
      await expect(
        service.update(orgId, 'prod_123', { slug: 'existing-slug' })
      ).rejects.toThrow(AppException);
    });

    it('should update allergens when provided', async () => {
      // Arrange
      const existingProduct = createMockProduct();
      const updatedProduct = createMockProduct();
      mockProductRepository.findByIdOrThrow.mockResolvedValue(existingProduct);
      mockProductRepository.update.mockResolvedValue(updatedProduct);
      mockProductRepository.setAllergens.mockResolvedValue(undefined);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.update(orgId, 'prod_123', {
        allergenIds: ['allergen_1', 'allergen_2'],
      });

      // Assert
      expect(mockProductRepository.setAllergens).toHaveBeenCalledWith(
        'prod_123',
        ['allergen_1', 'allergen_2']
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Availability Operations Tests
  // ---------------------------------------------------------------------------

  describe('updateAvailability', () => {
    it('should update product availability', async () => {
      // Arrange
      const availableProduct = createMockProduct({ isAvailable: true });
      const unavailableProduct = createMockProduct({ isAvailable: false });
      mockProductRepository.findByIdOrThrow.mockResolvedValue(availableProduct);
      mockProductRepository.update.mockResolvedValue(unavailableProduct);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.updateAvailability(orgId, 'prod_123', false);

      // Assert
      expect(result.product.isAvailable).toBe(false);
      expect(result.message).toContain('unavailable');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'product.availability.changed',
        expect.any(Object)
      );
    });

    it('should skip update if availability is unchanged', async () => {
      // Arrange
      const product = createMockProduct({ isAvailable: true });
      mockProductRepository.findByIdOrThrow.mockResolvedValue(product);

      // Act
      const result = await service.updateAvailability(orgId, 'prod_123', true);

      // Assert
      expect(result.message).toContain('already available');
      expect(mockProductRepository.update).not.toHaveBeenCalled();
    });
  });

  describe('toggleAvailability', () => {
    it('should toggle product availability from true to false', async () => {
      // Arrange
      const availableProduct = createMockProduct({ isAvailable: true });
      const unavailableProduct = createMockProduct({ isAvailable: false });
      mockProductRepository.findByIdOrThrow
        .mockResolvedValueOnce(availableProduct)
        .mockResolvedValueOnce(availableProduct);
      mockProductRepository.update.mockResolvedValue(unavailableProduct);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.toggleAvailability(orgId, 'prod_123');

      // Assert
      expect(result.product.isAvailable).toBe(false);
    });
  });

  describe('toggleFeatured', () => {
    it('should toggle product featured status', async () => {
      // Arrange
      const notFeatured = createMockProduct({ isFeatured: false });
      const featured = createMockProduct({ isFeatured: true });
      mockProductRepository.findByIdOrThrow.mockResolvedValue(notFeatured);
      mockProductRepository.update.mockResolvedValue(featured);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.toggleFeatured(orgId, 'prod_123');

      // Assert
      expect(result.isFeatured).toBe(true);
    });
  });

  // ---------------------------------------------------------------------------
  // Reorder Operations Tests
  // ---------------------------------------------------------------------------

  describe('reorder', () => {
    it('should reorder products successfully', async () => {
      // Arrange
      const reorderItems = [
        { id: 'prod_1', sortOrder: 0 },
        { id: 'prod_2', sortOrder: 1 },
      ];
      mockCategoryRepository.findByIdOrThrow.mockResolvedValue(createMockCategory());
      mockProductRepository.reorder.mockResolvedValue(undefined);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.reorder(orgId, categoryId, reorderItems);

      // Assert
      expect(result.count).toBe(2);
      expect(result.message).toContain('successfully');
      expect(mockProductRepository.reorder).toHaveBeenCalledWith(
        orgId,
        categoryId,
        reorderItems
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Delete Operations Tests
  // ---------------------------------------------------------------------------

  describe('delete', () => {
    it('should soft delete a product successfully', async () => {
      // Arrange
      const product = createMockProduct();
      mockProductRepository.findByIdOrThrow.mockResolvedValue(product);
      mockProductRepository.softDelete.mockResolvedValue(undefined);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.delete(orgId, 'prod_123');

      // Assert
      expect(mockProductRepository.softDelete).toHaveBeenCalledWith('prod_123', orgId);
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'product.deleted',
        expect.objectContaining({
          productId: product.id,
        })
      );
    });
  });

  describe('restore', () => {
    it('should restore a soft-deleted product', async () => {
      // Arrange
      const restoredProduct = createMockProduct();
      mockProductRepository.restore.mockResolvedValue(restoredProduct);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.restore(orgId, 'prod_123');

      // Assert
      expect(result).toEqual(restoredProduct);
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'product.restored',
        expect.any(Object)
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Variant Operations Tests
  // ---------------------------------------------------------------------------

  describe('getVariants', () => {
    it('should return variants for a product', async () => {
      // Arrange
      const variants = [
        createMockVariant(),
        createMockVariant({ id: 'var_456', name: 'Large', price: 150 }),
      ];
      mockProductRepository.findByIdOrThrow.mockResolvedValue(createMockProduct());
      mockProductRepository.findVariants.mockResolvedValue(variants);

      // Act
      const result = await service.getVariants(orgId, 'prod_123');

      // Assert
      expect(result).toEqual(variants);
    });
  });

  describe('createVariant', () => {
    it('should create a variant successfully', async () => {
      // Arrange
      const createdVariant = createMockVariant({ name: 'Medium', price: 125 });
      mockProductRepository.findByIdOrThrow.mockResolvedValue(createMockProduct());
      mockProductRepository.createVariant.mockResolvedValue(createdVariant);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.createVariant(orgId, {
        productId: 'prod_123',
        name: 'Medium',
        price: 125,
      });

      // Assert
      expect(result.variant).toEqual(createdVariant);
      expect(result.message).toContain('successfully');
    });
  });

  describe('updateVariant', () => {
    it('should update a variant successfully', async () => {
      // Arrange
      const updatedVariant = createMockVariant({ name: 'Updated', price: 175 });
      mockProductRepository.findByIdOrThrow.mockResolvedValue(createMockProduct());
      mockProductRepository.updateVariant.mockResolvedValue(updatedVariant);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.updateVariant(orgId, 'prod_123', 'var_123', {
        name: 'Updated',
        price: 175,
      });

      // Assert
      expect(result.variant).toEqual(updatedVariant);
    });

    it('should set as default when requested', async () => {
      // Arrange
      const updatedVariant = createMockVariant({ isDefault: true });
      mockProductRepository.findByIdOrThrow.mockResolvedValue(createMockProduct());
      mockProductRepository.updateVariant.mockResolvedValue(updatedVariant);
      mockProductRepository.setDefaultVariant.mockResolvedValue(undefined);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.updateVariant(orgId, 'prod_123', 'var_123', {
        isDefault: true,
      });

      // Assert
      expect(mockProductRepository.setDefaultVariant).toHaveBeenCalledWith(
        'var_123',
        'prod_123'
      );
    });
  });

  describe('deleteVariant', () => {
    it('should delete a variant successfully', async () => {
      // Arrange
      mockProductRepository.findByIdOrThrow.mockResolvedValue(createMockProduct());
      mockProductRepository.deleteVariant.mockResolvedValue(undefined);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.deleteVariant(orgId, 'prod_123', 'var_123');

      // Assert
      expect(mockProductRepository.deleteVariant).toHaveBeenCalledWith(
